// 1. Obtenemos el ítem de entrada actual de este nodo
const item = $input.first();

// 2. Traemos de forma correcta los datos del nodo de Switch1 usando encadenamiento opcional
const evolutionData = $('Switch1').first()?.json || {};

// 3. Extraemos el mensaje buscando en orden de prioridad (Texto normal -> Transcripción de Audio -> Entrada directa)
item.json.mensaje_unificado =
  $('Edit Fields1').first()?.json?.body?.data?.message?.conversation ||
  evolutionData?.message ||
  $input.first()?.json?.message || 
  "";

// 4. Extraemos el teléfono limpio buscando primero en Edit Fields1, luego en Switch1 y finalmente en la entrada
const phoneFromFields = $('Edit Fields1').first()?.json?.body?.data?.message?.telefono;
const phoneFromSwitch = evolutionData?.body?.data?.key?.remoteJid;
const phoneFromInput = $input.first()?.json?.telefono;

const rawPhone = phoneFromFields || phoneFromSwitch || phoneFromInput || "";

// Limpiamos el formato de WhatsApp para dejar solo los números
item.json.telefono = rawPhone.replace('@s.whatsapp.net', '').replace(/^521?/, '');

// 5. Devolvemos el ítem con los nuevos campos estructurados
return item;

// Este código toma la cadena de texto Base64 y la reconstruye en el archivo binario 'data' que busca Gemini
for (const item of $input.all()) {
  if (item.json && item.json.base64) {
    item.binary = {
      data: {
        data: item.json.base64,
        mimeType: 'audio/ogg',
        fileExtension: 'ogg',
        fileName: 'audio.ogg'
      }
    };
  }
}
return $input.all();

