// 1. Obtener la fecha y hora actual del sistema
const ahora = new Date();

// 2. Convertir el día y la hora a la zona horaria de Monterrey
const horaMonterreyTexto = ahora.toLocaleString("en-US", { timeZone: "America/Monterrey", hour: "2-digit", hour12: false });
const diaMonterreyTexto = ahora.toLocaleString("en-US", { timeZone: "America/Monterrey", weekday: "long" });

// 3. Convertir la hora a un número entero (0 a 23)
const horaActual = parseInt(horaMonterreyTexto, 10);

// 4. Definir variables de control
let estaAbierto = false;
const horaApertura = 8; // 8:00 AM para todos los días

// 5. Validar el horario según el día de la semana
// Los días en toLocaleString de "en-US" devuelven: Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday
if (["Monday", "Tuesday", "Wednesday", "Thursday"].includes(diaMonterreyTexto)) {
  // Lunes a Jueves: 8:00 AM a 1:00 PM (Hora 13)
  const horaCierreSemana = 13;
  if (horaActual >= horaApertura && horaActual < horaCierreSemana) {
    estaAbierto = true;
  }
} else if (["Friday", "Saturday", "Sunday"].includes(diaMonterreyTexto)) {
  // Viernes a Domingo: 8:00 AM a 2:00 PM (Hora 14)
  const horaCierreFin = 14;
  if (horaActual >= horaApertura && horaActual < horaCierreFin) {
    estaAbierto = true;
  }
}

// 6. Enviar el resultado al siguiente nodo de n8n
return {
  json: {
    estaAbierto: estaAbierto,
    horaDetectada: horaActual,
    diaDetectado: diaMonterreyTexto
  }
};
